CREATE TABLE `inventory_asset` (
 `id` varchar(36) NOT NULL, `tenant_id` varchar(36) NOT NULL, `inventory_code` varchar(50) NOT NULL, `normalized_inventory_code` varchar(50) NOT NULL, `name` varchar(150) NOT NULL, `normalized_name` varchar(150) NOT NULL, `category` varchar(100) NOT NULL, `tracking_mode` enum('grouped','individual') NOT NULL, `condition` enum('good','damaged','maintenance','lost') NOT NULL, `quantity` int NOT NULL, `location_id` varchar(36), `acquisition_date` date, `acquisition_cost` int, `acquisition_source` varchar(150), `archived` boolean NOT NULL DEFAULT false, `archived_at` timestamp(3), `archive_reason` varchar(1000), `version` int NOT NULL DEFAULT 1, `created_at` timestamp(3) NOT NULL, `updated_at` timestamp(3) NOT NULL,
 CONSTRAINT `inventory_asset_id` PRIMARY KEY(`id`), CONSTRAINT `inventory_asset_tenant_id_id_unique` UNIQUE(`tenant_id`,`id`), CONSTRAINT `inventory_asset_tenant_code_unique` UNIQUE(`tenant_id`,`normalized_inventory_code`), CONSTRAINT `inventory_asset_tenant_fkey` FOREIGN KEY (`tenant_id`) REFERENCES `tenant`(`id`), CONSTRAINT `inventory_asset_tenant_location_fkey` FOREIGN KEY (`tenant_id`,`location_id`) REFERENCES `location`(`tenant_id`,`id`), CONSTRAINT `inventory_asset_quantity_check` CHECK (`quantity` >= 0 AND (`tracking_mode` = 'grouped' OR `quantity` = 1)), CONSTRAINT `inventory_asset_cost_check` CHECK (`acquisition_cost` IS NULL OR `acquisition_cost` >= 0), CONSTRAINT `inventory_asset_version_check` CHECK (`version` > 0)
);
